    60	    /// <inheritdoc />
    61	    public async Task<IReadOnlyList<InventoryBalance>> ListBalancesAsync(Guid workspaceId, Guid? warehouseId, Guid? productId,
    62	        CancellationToken cancellationToken)
    63	    {
    64	        var query = dbContext.InventoryBalances.AsNoTracking().Where(balance => balance.WorkspaceId == workspaceId);
    65	        if (warehouseId.HasValue) query = query.Where(balance => balance.WarehouseId == warehouseId.Value);
    66	        if (productId.HasValue) query = query.Where(balance => balance.ProductId == productId.Value);
    67	        return await query.OrderBy(balance => balance.WarehouseId).ThenBy(balance => balance.ProductId).ToListAsync(cancellationToken);
    68	    }
    69	}
