    12	namespace InventoryFlow.Api.ExceptionHandling;
    13	
    14	/// <summary>
    15	/// Converts unhandled application exceptions into RFC 7807 problem details responses.
    16	/// </summary>
    17	/// <param name="logger">The logger used to capture unexpected failures.</param>
    18	public sealed class GlobalExceptionHandler(
    19	    ILogger<GlobalExceptionHandler> logger) : IExceptionHandler
    20	{
    21	    /// <inheritdoc />
    22	    public async ValueTask<bool> TryHandleAsync(
    23	        HttpContext httpContext,
    24	        Exception exception,
    25	        CancellationToken cancellationToken)
    26	    {
    27	        if (httpContext.Response.HasStarted)
    28	        {
    29	            logger.LogWarning(
    30	                exception,
    31	                "The response has already started for {RequestMethod} {RequestPath}",
    32	                httpContext.Request.Method,
    33	                httpContext.Request.Path);
    34	
    35	            return false;
    36	        }
    37	
    38	        var statusCode = exception switch
    39	        {
    40	            ValidationException => StatusCodes.Status400BadRequest,
    41	            DomainException => StatusCodes.Status400BadRequest,
    42	            AuthenticationException => StatusCodes.Status401Unauthorized,
    43	            ProductSkuConflictException => StatusCodes.Status409Conflict,
    44	            SupplierNameConflictException => StatusCodes.Status409Conflict,
    45	            WarehouseNameConflictException => StatusCodes.Status409Conflict,
    46	            InsufficientInventoryException => StatusCodes.Status409Conflict,
    47	            InventoryArchiveConflictException => StatusCodes.Status409Conflict,
    48	            _ => StatusCodes.Status500InternalServerError,
    49	        };
    50	
    51	        logger.LogError(
    52	            exception,
    53	            "Unhandled exception while processing {RequestMethod} {RequestPath}",
    54	            httpContext.Request.Method,
    55	            httpContext.Request.Path);
    56	
    57	        if (exception is ValidationException validationException)
    58	        {
    59	            var validation = new ValidationProblemDetails(validationException.Errors.GroupBy(error => error.PropertyName).ToDictionary(group => group.Key, group => group.Select(error => error.ErrorMessage).ToArray()))
    60	            { Status = statusCode, Title = "One or more validation errors occurred.", Type = "https://tools.ietf.org/html/rfc9110#section-15.5.1" };
    61	            httpContext.Response.StatusCode = statusCode;
    62	            await httpContext.Response.WriteAsJsonAsync(validation, options: null, contentType: "application/problem+json", cancellationToken: cancellationToken);
    63	            return true;
    64	        }
    65	
    66	        var problemDetails = new ProblemDetails
    67	        {
    68	            Status = statusCode,
    69	            Title = statusCode switch { StatusCodes.Status400BadRequest => "A business rule was violated.", StatusCodes.Status401Unauthorized => "Authentication failed.", StatusCodes.Status409Conflict => "A conflicting value or insufficient inventory exists.", _ => "An unexpected error occurred." },
    70	            Type = statusCode switch
    71	            {
    72	                StatusCodes.Status400BadRequest => "https://tools.ietf.org/html/rfc9110#section-15.5.1",
    73	                StatusCodes.Status409Conflict => "https://tools.ietf.org/html/rfc9110#section-15.5.10",
    74	                _ => "https://tools.ietf.org/html/rfc9110#section-15.6.1",
    75	            },
    76	            Detail = exception is DomainException or InsufficientInventoryException or InventoryArchiveConflictException
    77	                ? exception.Message
    78	                : null,
    79	        };
    80	
    81	        httpContext.Response.StatusCode = statusCode;
    82	        await httpContext.Response.WriteAsJsonAsync(
    83	            problemDetails,
    84	            options: null,
    85	            contentType: "application/problem+json",
    86	            cancellationToken: cancellationToken);
    87	
    88	        return true;
    89	    }
    90	}
