    15	const suppliersKey = (userId: string, workspaceId: string) =>
    16	  ["suppliers", userId, workspaceId] as const
    17	
    18	const readError = (error: unknown) => {
    19	  if (typeof error === "object" && error && "response" in error) {
    20	    const data = (
    21	      error as { response?: { data?: { detail?: string; title?: string } } }
    22	    ).response?.data
    23	    return data?.detail ?? data?.title ?? "Unable to save the supplier."
    24	  }
    25	  return "Unable to save the supplier."
    26	}
    27	
    28	export function Component() {
