    30	public static class InfrastructureServiceCollectionExtensions
    31	{
    32	    /// <summary>
    33	    /// Adds SQL Server persistence and ASP.NET Core Identity services.
    34	    /// </summary>
    35	    /// <param name="services">The dependency-injection service collection.</param>
    36	    /// <param name="configuration">The application configuration.</param>
    37	    /// <returns>The supplied <paramref name="services"/> instance.</returns>
    38	    /// <exception cref="ArgumentException">Thrown when the database connection string is missing.</exception>
    39	    public static IServiceCollection AddInfrastructure(
    40	        this IServiceCollection services,
    41	        IConfiguration configuration)
    42	    {
    43	        ArgumentNullException.ThrowIfNull(services);
    44	        ArgumentNullException.ThrowIfNull(configuration);
    45	
    46	        var connectionString = configuration.GetConnectionString("InventoryFlowDatabase");
    47	        ArgumentException.ThrowIfNullOrWhiteSpace(
    48	            connectionString,
    49	            "ConnectionStrings:InventoryFlowDatabase");
    50	
    51	        services.AddOptions<JwtOptions>()
    52	            .Bind(configuration.GetSection(JwtOptions.SectionName))
    53	            .ValidateDataAnnotations()
    54	            .Validate(options => Encoding.UTF8.GetByteCount(options.SigningKey) >= 32, "Jwt signing key must be at least 32 bytes.")
    55	            .ValidateOnStart();
    56	        var jwt = configuration.GetSection(JwtOptions.SectionName).Get<JwtOptions>() ?? new JwtOptions();
    57	
    58	        services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
    59	            .AddJwtBearer(options =>
    60	            {
    61	                options.TokenValidationParameters = new TokenValidationParameters
    62	                {
    63	                    ValidateIssuer = true,
    64	                    ValidIssuer = jwt.Issuer,
    65	                    ValidateAudience = true,
    66	                    ValidAudience = jwt.Audience,
    67	                    ValidateIssuerSigningKey = true,
    68	                    IssuerSigningKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwt.SigningKey)),
    69	                    ValidateLifetime = true,
    70	                    ClockSkew = TimeSpan.Zero,
    71	                    NameClaimType = "display_name"
    72	                };
    73	            });
    74	        services.AddHttpContextAccessor();
    75	        services.AddSingleton(TimeProvider.System);
    76	        services.AddScoped<ICurrentWorkspace, CurrentWorkspaceResolver>();
    77	        services.AddScoped<JwtAccessTokenIssuer>();
    78	        services.AddSingleton<RefreshTokenGenerator>();
    79	        services.AddScoped<IAuthenticationService, IdentityAuthenticationService>();
    80	        services.AddScoped<IProductCatalog, EfProductCatalog>();
    81	        services.AddScoped<IWarehouseCatalog, EfWarehouseCatalog>();
    82	        services.AddScoped<ISupplierCatalog, EfSupplierCatalog>();
    83	        services.AddScoped<IInventoryLedger, EfInventoryLedger>();
    84	
    85	        services.AddDbContext<ApplicationDbContext>(options => options.UseSqlServer(
    86	            connectionString,
    87	            sqlServerOptions => sqlServerOptions.EnableRetryOnFailure()));
    88	        services.AddDataProtection()
    89	            .SetApplicationName("InventoryFlow")
    90	            .PersistKeysToDbContext<ApplicationDbContext>();
    91	
    92	        services.AddIdentityCore<ApplicationUser>(options =>
    93	            {
    94	                options.User.RequireUniqueEmail = true;
